// supplier-auth.service.ts
import { Injectable, inject } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';
import { BehaviorSubject } from 'rxjs';
import { AuthService } from './Base/auth.service';

// INTERFACCE CORRETTE
export interface SupplierProfile {
  id: string;
  user_id: string;
  company_name: string;
  contact_name?: string;
  email?: string;
  phone?: string;
  address?: string;
  description?: string;
  is_platform_supplier: boolean;
  is_approved: boolean;
  created_at: string;
}

export interface RestaurantInfo {
  id: string;
  name: string;
  email?: string;
  phone?: string;
  address?: string;
}

export interface SupplierIngredient {
  id: string;
  name: string;
  description?: string;
  current_stock: number;
  minimum_stock: number;
  cost_per_unit: number;
  restaurant_name: string;
  restaurant_id: string;
  created_at: string;
}

// Interface per i dati della query restaurants
interface RestaurantQueryResult {
  restaurant_id: string;
  restaurants: RestaurantInfo;
}

// Interface per i dati della query ingredients
interface IngredientQueryResult {
  id: string;
  name: string;
  description?: string;
  current_stock: number;
  minimum_stock: number;
  cost_per_unit: number;
  created_at: string;
  restaurant_id: string;
  restaurants: { name: string };
}

@Injectable({
  providedIn: 'root'
})
export class SupplierAuthService {
  private supabaseService = inject(SupabaseService);
  private authService = inject(AuthService);

  private supplierProfileSubject = new BehaviorSubject<SupplierProfile | null>(null);
  public supplierProfile$ = this.supplierProfileSubject.asObservable();

  async loadSupplierProfile(): Promise<void> {
    try {
      const user = this.authService.currentUserValue;
      if (!user) {
        console.error('No user authenticated');
        return;
      }

      const { data: supplier, error } = await this.supabaseService.getSupabaseClient()
        .from('suppliers')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (error) {
        console.error('Error loading supplier profile:', error);
        return;
      }

      this.supplierProfileSubject.next(supplier);
    } catch (error) {
      console.error('Error in loadSupplierProfile:', error);
    }
  }

  async getSupplierRestaurants(): Promise<RestaurantInfo[]> {
    try {
      const supplier = this.supplierProfileSubject.value;
      if (!supplier) return [];

      // Query CORRETTA: trova ristoranti distinti che usano i prodotti di questo fornitore
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('ingredients')
        .select(`
          restaurant_id,
          restaurants!inner (
            id,
            name,
            email,
            phone,
            address
          )
        `)
        .eq('supplier_id', supplier.id)
        .not('restaurant_id', 'is', null);

      if (error) {
        console.error('Error loading supplier restaurants:', error);
        return [];
      }

      // Cast esplicito del tipo
      const restaurantData = data as unknown as RestaurantQueryResult[];
      
      // Estrai i ristoranti unici
      const restaurants = restaurantData.map(item => item.restaurants);
      const distinctRestaurants = restaurants.filter((restaurant, index, self) => 
        index === self.findIndex(r => r.id === restaurant.id)
      );

      return distinctRestaurants;
    } catch (error) {
      console.error('Error loading supplier restaurants:', error);
      return [];
    }
  }

  async getSupplierIngredients(): Promise<SupplierIngredient[]> {
    try {
      const supplier = this.supplierProfileSubject.value;
      if (!supplier) return [];

      // Query CORRETTA: ingredienti con nome ristorante
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('ingredients')
        .select(`
          id,
          name,
          description,
          current_stock,
          minimum_stock,
          cost_per_unit,
          created_at,
          restaurant_id,
          restaurants!inner (name)
        `)
        .eq('supplier_id', supplier.id)
        .order('name');

      if (error) {
        console.error('Error loading supplier ingredients:', error);
        return [];
      }

      // Cast esplicito del tipo
      const ingredientsData = data as unknown as IngredientQueryResult[];

      // Trasforma i dati nel formato corretto
      return ingredientsData.map(item => ({
        id: item.id,
        name: item.name,
        description: item.description,
        current_stock: item.current_stock,
        minimum_stock: item.minimum_stock,
        cost_per_unit: item.cost_per_unit,
        restaurant_name: item.restaurants.name || 'N/D',
        restaurant_id: item.restaurant_id,
        created_at: item.created_at
      }));
    } catch (error) {
      console.error('Error loading supplier ingredients:', error);
      return [];
    }
  }

  getSupplierProfile(): SupplierProfile | null {
    return this.supplierProfileSubject.value;
  }

  // Aggiorna profilo fornitore
  async updateSupplierProfile(updates: Partial<SupplierProfile>): Promise<boolean> {
    try {
      const supplier = this.supplierProfileSubject.value;
      if (!supplier) return false;

      const { error } = await this.supabaseService.getSupabaseClient()
        .from('suppliers')
        .update(updates)
        .eq('id', supplier.id);

      if (error) throw error;
      
      // Ricarica il profilo
      await this.loadSupplierProfile();
      return true;
    } catch (error) {
      console.error('Error updating supplier profile:', error);
      return false;
    }
  }
}